<?php namespace App\Domains\Furniture\Policies; use Illuminate\Auth\Access\HandlesAuthorization; class FurnitureItemPolicy { use HandlesAuthorization; public function viewAny($user) { return true; } public function view($user, $furniture) { return $user->tenant_id === $furniture->tenant_id; } public function create($user) { return true; } public function update($user, $furniture) { return $user->tenant_id === $furniture->tenant_id; } public function delete($user, $furniture) { return $user->tenant_id === $furniture->tenant_id; } }
